$164e443d = ""
function Load-LemonHerb {
$fb = [Convert]::FromBase64String($164e443d)
for($i=0; $i -lt $fb.count ; $i++) {$fb[$i] = $fb[$i] -bxor 0x66}
[System.Reflection.Assembly]::Load($fb)
}
$asm = Load-LemonHerb
function Invoke-LemonHerb { param([Parameter ()] $Args = "")
$Args -eq "" -and ($Args = Read-Host "Specify command arguments")
$asm.GetType("PingCastle.Program", [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
$asm.GetType([PingCastle.Program], [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
}
Invoke-LemonHerb
